SELECT AVG(usage_amount) AS average_memory_usage
FROM memory_usage_logs
WHERE user_id IN (
    SELECT user_id FROM users WHERE role = 'administrator'
) AND device_id IN (
    SELECT device_id FROM devices WHERE is_active = 1
);

SELECT device_id, SUM(usage_amount) AS total_usage
FROM memory_usage_logs
GROUP BY device_id;

SELECT region_id, usage_amount, timestamp, notes
FROM memory_usage_logs
WHERE usage_amount > 512 AND device_id = 1;

SELECT log_id, usage_amount
FROM memory_usage_logs
WHERE log_id > 100 AND usage_amount > 1000;

SELECT *
FROM memory_types
WHERE is_deprecated = 0;
